const inputData = $input.all(); // 获取所有输入
let whereConditions = ['dod.watch_status = \'1\'']; // 默认添加watch_status条件

// 如果inputData数组中至少有一个元素，并且第一个元素包含json对象
if (inputData.length > 0 && inputData[0].json) {
  const queries = inputData[0].json; // 获取实际的查询参数

  // 排除Status字段
  delete queries['Status'];
  delete queries['InboundDate_End'];
  delete queries['InboundDate_Start'];

  // 遍历queries的键值对
  for (const [key, value] of Object.entries(queries)) {
    if (key === 'ActiveDate_End' || key === 'ActiveDate_Start') continue; // 跳过ActiveDate_End, ActiveDate_Start

    if (value && value !== "0") { // 如果键有非"0"值，构造条件并添加到数组
      if (key === 'order_number') {
        // 使用LIKE进行模糊匹配
        const orderNumbers = value.split(';').filter(v => v.trim() !== '');
        if (orderNumbers.length > 0) {
          orderNumbers.forEach(orderNumber => {
            whereConditions.push(`dod.order_number LIKE '%${orderNumber.trim()}%'`);
          });
        }
      } else if (key === 'retroid') {
        whereConditions.push(`dod.${key} = '${value}'`);
      } else {
        whereConditions.push(`dod.${key} = '${value}'`); // 注意，这里应该根据实际情况决定是否要加引号
      }
    }
  }

  // 处理ActiveDate_Start和ActiveDate_End，仅当有非"0"的有效值时添加条件
  if (queries['ActiveDate_Start'] && queries['ActiveDate_Start'] !== '0') {
    whereConditions.push(`dod.create_time >= '${queries['ActiveDate_Start']} 00:00:00'`);
  }
  if (queries['ActiveDate_End'] && queries['ActiveDate_End'] !== '0') {
    whereConditions.push(`dod.create_time <= '${queries['ActiveDate_End']} 23:59:59'`);
  }
}

// 构建SQL查询语句
const sqlQuery = `
SELECT DISTINCT dod.id, dod.retroid, dod.uuid, dod.watchtype, dod.price, dod.order_number, 
                dod.create_time, dod.watch_status, dod.sku_code, dod.uuid_unique, dod.sku_name, 
                MAX(pt.trial_expiration_date) AS trial_expiration_date
FROM public.delivery_order_details dod
JOIN public.prototype_trial pt ON dod.order_number = ANY(pt.order_number)
WHERE ${whereConditions.join(' AND ')} AND pt.trial_expiration_date > now()
GROUP BY dod.id, dod.retroid, dod.uuid, dod.watchtype, dod.price, dod.order_number, 
         dod.create_time, dod.watch_status, dod.sku_code, dod.uuid_unique, dod.sku_name;
`;

// 返回sqlQuery
return { sqlQuery: sqlQuery };

